request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?source ?sourceName ?target ?targetName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef ?source .
  ?edge bbo:has_targetRef ?target .
  {
    ?source bbo:name "Record time and incident report in service form" .
  }
  UNION
  {
    ?target bbo:name "Record time and incident report in service form" .
  }
  UNION
  {
    ?source bbo:name "End the call with a good note" .
  }
  UNION
  {
    ?target bbo:name "End the call with a good note" .
  }
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?nodeName WHERE {
  ?node a ?type .
  ?node bbo:id "sid-3545D44C-4ED5-43E2-8C14-99949AECB865" .
  OPTIONAL { ?node bbo:name ?nodeName . }
}
